create table public.repasses_gestao(id uuid primary key default gen_random_uuid(),loja_id uuid not null references public.lojas(id),gestao_origem_id uuid not null references public.administracoes(id),gestao_destino_id uuid references public.administracoes(id),prestacao_final_id uuid references public.prestacoes_finais(id),status text not null default 'Em elaboração' check(status in('Em elaboração','Em conferência','Pronto para assinatura','Finalizado','Cancelado')),data_referencia date not null default current_date,data_repasse date,caixa numeric(14,2) not null default 0 check(caixa>=0),banco numeric(14,2) not null default 0 check(banco>=0),creditos numeric(14,2) not null default 0 check(creditos>=0),obrigacoes numeric(14,2) not null default 0 check(obrigacoes>=0),saldo_liquido numeric(14,2) generated always as(caixa+banco+creditos-obrigacoes) stored,pendencias_financeiras text,pendencias_administrativas text,documentos_pendentes text,observacoes text,justificativa_divergencia text,responsavel_repasse_id uuid references public.obreiros(id),responsavel_recebimento_id uuid references public.obreiros(id),finalizado_em timestamptz,criado_em timestamptz default now(),atualizado_em timestamptz default now(),unique(gestao_origem_id));
alter table public.repasses_gestao enable row level security;create policy "repasse leitura" on public.repasses_gestao for select to authenticated using(public.usuario_pertence_loja(loja_id));create policy "repasse escrita" on public.repasses_gestao for all to authenticated using(public.usuario_pode_escrever(loja_id,'/configuracoes')) with check(public.usuario_pode_escrever(loja_id,'/configuracoes'));
create or replace function public.preparar_repasse() returns trigger language plpgsql as $$ begin if tg_op='UPDATE' and old.status='Finalizado' then raise exception 'Repasse finalizado está protegido';end if;if new.status='Finalizado' then if new.data_repasse is null or new.responsavel_repasse_id is null then raise exception 'Data e responsável são obrigatórios';end if;new.finalizado_em=now();update public.administracoes set status='Encerrada',ativa=false where id=new.gestao_origem_id;update public.prestacoes_finais set status='Bloqueada' where id=new.prestacao_final_id and status='Aprovada';end if;new.atualizado_em=now();return new;end $$;create trigger preparar_repasse before insert or update on public.repasses_gestao for each row execute function public.preparar_repasse();
create trigger auditoria_operacional after insert or update or delete on public.repasses_gestao for each row execute function public.registrar_auditoria_operacional();
